package main

import "testing"

// TestChangedRowCount pins the Go port of the frontend changedRows(blockRows(b))
// to the exact counts the real JS produces. The expected values were generated by
// running the verbatim Block.mjs functions (dedent4 → alignRows → changedRows) over
// the same fixtures; see the plan/commit notes. If the Go LCS ever drifts from the
// JS one, done/total in the UI would desync — this guards that.
func TestChangedRowCount(t *testing.T) {
	cases := []struct {
		name     string
		old, new string
		want     int
	}{
		{
			name: "modify_one",
			old:  "function f() {\n    return 1;\n}",
			new:  "function f() {\n    return 2;\n}",
			want: 1,
		},
		{
			// A removed line with no replacement is a filler row → counts as 1.
			name: "pure_delete",
			old:  "function f() {\n    $a = 1;\n    $b = 2;\n    return $a;\n}",
			new:  "function f() {\n    $a = 1;\n    return $a;\n}",
			want: 1,
		},
		{
			name: "pure_add",
			old:  "function f() {\n    return $a;\n}",
			new:  "function f() {\n    $log = true;\n    return $a;\n}",
			want: 1,
		},
		{
			// A whitespace-only re-indent must NOT count.
			name: "ws_only",
			old:  "function f() {\n    $a = array(1, 2);\n}",
			new:  "function f() {\n        $a = array(1, 2);\n}",
			want: 0,
		},
		{
			// One real change + one ws-only re-indent + one pure delete → 2.
			name: "mixed",
			old:  "function f() {\n    $a = 1;\n    $b = 2;\n    $c = 3;\n    return $a;\n}",
			new:  "function f() {\n    $a = 9;\n        $b = 2;\n    return $a;\n}",
			want: 2,
		},
		{
			name: "added_block",
			old:  "",
			new:  "function g() {\n    return 42;\n}",
			want: 3,
		},
		{
			name: "removed_block",
			old:  "function g() {\n    return 42;\n}",
			new:  "",
			want: 3,
		},
		{
			// dedent4 strips a uniform 4-space indent before aligning.
			name: "dedented",
			old:  "    function h() {\n        return 1;\n    }",
			new:  "    function h() {\n        return 2;\n    }",
			want: 1,
		},
	}
	for _, c := range cases {
		t.Run(c.name, func(t *testing.T) {
			if got := changedRowCount(c.old, c.new); got != c.want {
				t.Fatalf("changedRowCount(%s) = %d, want %d", c.name, got, c.want)
			}
		})
	}
}
